ps.pstext:
if !IsFeatureImplemented(FEAT_SME_F16F16) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 16;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);

if !IsFeatureImplemented(FEAT_SME) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 32;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);

if !IsFeatureImplemented(FEAT_SME_F64F64) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 64;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let dim : integer{} = VL DIV esize;
let mask1 : bits(PL) = P{}(a);
let mask2 : bits(PL) = P{}(b);
let op1 : bits(VL) = Z{}(n);
let op2 : bits(VL) = Z{}(m);
let op3 : bits(dim*dim*esize) = ZAtile{}(da, esize);
var result : bits(dim*dim*esize);

for row = 0 to dim-1 do
    for col = 0 to dim-1 do
        let elem2 : bits(esize) = op2[col*:esize];
        let elem3 : bits(esize) = op3[(row*dim+col)*:esize];

        if (ActivePredicateElement{PL}(mask1, row, esize) &&
              ActivePredicateElement{PL}(mask2, col, esize)) then
            let elem1 : bits(esize) = op1[row*:esize];
            result[(row*dim+col)*:esize] = FPMulAdd_ZA{esize}(elem3, elem1, elem2, FPCR());
        else
            result[(row*dim+col)*:esize] = elem3;
        end;
    end;
end;

ZAtile{dim*dim*esize}(da, esize) = result;
